def scan_tool_pii(message):
    for content in message.get('content', []):
        if content.get('type') == 'tool_use':
            args = content.get('input', {})
            args_str = str(args)
            for pattern in PII_PATTERNS:
                if re.search(pattern, args_str):
                    raise ValueError(f'PII detected in tool args: {args_str[:100]}...')
    return True

const PII_REGEX = /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b|\b\d{3}[-.]?\d{3}[-.]?\d{4}\b/g;

function interceptToolUse(messages: any[]): boolean {
  for (const msg of messages) {
    if (msg.role === 'user' && msg.content?.some((c: any) => c.type === 'tool_use')) {
      const toolContent = msg.content.find((c: any) => c.type === 'tool_use');
      const argsStr = JSON.stringify(toolContent.input);
      const matches = argsStr.match(PII_REGEX);
      if (matches) {
        throw new Error(`PII detected in tool_use: ${matches.slice(0, 3).join(', ')}`);
      }
    }
  }
  return true;
}

