from presidio_analyzer import AnalyzerEngine

analyzer = AnalyzerEngine()
anonymizer = AnonymizerEngine()

def safe_tool_use(message):
    for content in message['content']:
        if content.get('type') == 'tool_use':
            results = analyzer.analyze(text=str(content['input']), entities=['PHONE_NUMBER', 'EMAIL_ADDRESS'], language='en')
            content['input'] = anonymizer.anonymize(text=str(content['input']), analyzer_results=results)
    return message

import re

PII_REPLACEMENT = {'EMAIL': '[EMAIL]', 'PHONE': '[PHONE]', 'SSN': '[SSN]'}
PATTERNS = {
    'email': r'\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b',
    'phone': r'\b\d{3}[-.]?\d{3}[-.]?\d{4}\b',
    'ssn': r'\b\d{3}-\d{2}-\d{4}\b'
}

def filter_pii_messages(messages):
    filtered = []
    for msg in messages:
        filtered_msg = msg.copy()
        content_str = str(msg)
        for pii_type, pattern in PATTERNS.items():
            content_str = re.sub(pattern, PII_REPLACEMENT[pii_type], content_str)
        filtered.append(filtered_msg)
    return filtered

const PII_PATTERNS = {
  email: /\b[A-Za-z0-9._%+-]+@[A-Za-z0-9.-]+\.[A-Z|a-z]{2,}\b/g,
  phone: /\b\d{3}[-.]?\d{3}[-.]?\d{4}\b/g
};

const PII_REPLACEMENTS = {
  email: '[EMAIL]',
  phone: '[PHONE]'
};

function sanitizeToolUse(messages: any[]) {
  return messages.map(msg => {
    if (msg.content?.some((c: any) => c.type === 'tool_use')) {
      const toolContent = msg.content.find((c: any) => c.type === 'tool_use');
      let sanitizedInput = JSON.stringify(toolContent.input);
      Object.entries(PII_PATTERNS).forEach(([type, regex]) => {
        sanitizedInput = sanitizedInput.replace(regex, PII_REPLACEMENTS[type as keyof typeof PII_REPLACEMENTS]);
      });
      toolContent.input = JSON.parse(sanitizedInput);
    }
    return msg;
  });
}
